// Each Server-Sent Event (SSE) frame looks like:
//   data: {"type":"delta","text":"Here are"}
//   data: {"type":"tool","result":{...labCards...}}
//   data: {"type":"done","messageId":"abc"}

export async function streamChat(
  body: ChatRequest,
  onEvent: (e: StreamEvent) => void
) {
  const res = await fetch('/api/chat/stream', {
    method: 'POST',
    body: JSON.stringify(body),
    headers: { 'Content-Type': 'application/json' },
  });

  const reader = res.body!.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });

    // SSE frames are separated by double newlines
    const parts = buffer.split('\n\n');
    buffer = parts.pop() ?? ''; // keep incomplete last frame

    for (const part of parts) {
      const line = part.replace(/^data: /, '').trim();
      if (!line) continue;
      const event = JSON.parse(line) as StreamEvent;
      onEvent(event); // 'delta' appends text, 'tool' shows cards
    }
  }
}
